import javax.swing.*;
public class SlowAction {
    public static void main(String[] args) {
        JButton btn = new JButton("Fetch Data");
        btn.addActionListener(e -> {
            try {
                Thread.sleep(5000);  // simulates slow network call
                btn.setText("Done");
            } catch (InterruptedException ex) { ex.printStackTrace(); }
        });
        JFrame f = new JFrame();
        f.add(btn);
        f.pack();
        f.setVisible(true);
    }
}
